  ('heelevel3-c8735cdb-moex-00289', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-110-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '訴願人提起訴願，請求為特定內容之行政處分，在訴願決定作成前，應作為之機關已作成不利於 訴願人之行政處分。受理訴願機關應為如何之處置？', '["應以訴願為不合法，為不受理之決定", "應逕認訴願為無理由，以決定駁回之", "應逕認訴願為有理由者，將原處分撤銷", "應續行訴願程序，對嗣後所為之行政處分併為實體審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:18+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "332", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00290', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-110-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '有關訴願管轄之敘述，下列何者錯誤？', '["對縣政府辦理委辦事件所為之行政處分不服者，向縣政府之直接上級機關提起訴願", "對無隸屬關係之機關辦理受委託事件所為之行政處分不服者，向原委託機關或其直接上級機關 提起訴願", "對有隸屬關係之機關辦理受委任事件所為之行政處分不服者，向原委任機關之直接上級機關提 起訴願", "對受託行使公權力之個人所為之行政處分不服者，向原委託機關提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:18+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "332", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00291', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-110-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '關於行政訴訟訴訟費用之敘述，下列何者錯誤？', '["適用簡易訴訟程序之事件，徵收裁判費新臺幣2,000元", "適用通常訴訟程序之事件，按件徵收裁判費新臺幣4,000元", "訴訟費用原則上由敗訴之當事人負擔", "依行政訴訟法第198條為情況判決時，其訴訟費用由敗訴之原告負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:18+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "332", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00292', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-110-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '關於行政訴訟輔佐人之敘述，下列何者錯誤？', '["輔佐人經審判長許可得到場", "人數不得超過2人", "僅限當事人得申請輔佐人到場", "審判長認其不適當得撤銷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:18+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "332", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00293', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-110-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '行政機關依法實施即時強制，造成人民損害之補償，下列何者錯誤？', '["該損失補償，以回復原狀為原則，金錢補償為例外", "對於執行機關所為損失補償之決定不服，可依法提起訴願及行政訴訟", "損失補償，應於知有損失後，2年內向執行機關請求", "人民因執行機關依法實施即時強制，致其財產遭受特別損失，原則得請求補償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:18+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "332", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
  ('heelevel3-c8735cdb-moex-00294', 'heelevel3-c8735cdb', 'heelevel3-c8735cdb-moex-110-3082b5f1', 'sub-heelevel3-c8735cdb-03', NULL, 'single_choice', '公務員因作成或不作成行政處分，不法侵害人民權益者，請求國家賠償，下列何者錯誤？', '["於提起國家賠償前，原則上必須先進行行政爭訟請求救濟", "如行政爭訟程序已開始，民事法院無須停止國家賠償審判程序", "若人民於訴願期間向賠償義務機關表示不服請求協議賠償，致未依限提起訴願者，視為已遵期 提起訴願", "如行政法院判決已認行政處分不違法並予維持者，受理賠償訴訟之民事法院不得再自行審查行 政處分是否違法，而應以訴訟無理由駁回之"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:18+00:00", "source_pdf_sha1": "b59c20af004e", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "332", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "公平交易管理"}'::jsonb, NULL),
